import type { ReactNode } from "react";
import { cn } from "@/lib/utils";

export interface OdsSegmentedControlItem<TValue extends string> {
  disabled?: boolean;
  label: ReactNode;
  value: TValue;
}

interface OdsSegmentedControlProps<TValue extends string> {
  ariaLabel?: string;
  className?: string;
  disabled?: boolean;
  itemClassName?: string;
  items: ReadonlyArray<OdsSegmentedControlItem<TValue>>;
  onValueChange: (value: TValue) => void;
  value: TValue;
}

export function OdsSegmentedControl<TValue extends string>({
  ariaLabel,
  className,
  disabled = false,
  itemClassName,
  items,
  onValueChange,
  value,
}: OdsSegmentedControlProps<TValue>) {
  return (
    <div
      aria-label={ariaLabel}
      className={cn(
        "inline-flex h-8 items-center gap-1 rounded-[24px] border border-[var(--border-subtle)] bg-[var(--bg-secondary)] p-0.5",
        className
      )}
      role="radiogroup"
    >
      {items.map(item => {
        const isSelected = item.value === value;
        const isDisabled = disabled || item.disabled;

        return (
          <button
            aria-checked={isSelected}
            className={cn(
              "inline-flex h-7 items-center justify-center whitespace-nowrap rounded-[20px] px-3 text-[12px] font-medium leading-[120%] transition-[background-color,color,opacity]",
              isSelected
                ? "bg-[var(--bg-primary)] text-[var(--fg-base)]"
                : "text-[var(--fg-secondary)] hover:bg-[var(--bg-hover)] hover:text-[var(--fg-base)]",
              isDisabled && "pointer-events-none opacity-50",
              itemClassName
            )}
            disabled={isDisabled}
            key={item.value}
            onClick={() => {
              if (!isSelected) onValueChange(item.value);
            }}
            role="radio"
            type="button"
          >
            {item.label}
          </button>
        );
      })}
    </div>
  );
}
